import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { stockStrings } from '../../config';
import { TableCell, TextField } from '@material-ui/core';
import $ from 'jquery';

const style = theme => ({
    root: {
    }
})
class _NewStockCellMapFormat extends Component {
    constructor(props) {
        super(props);
        const {cellMap, row} = props;
        this.editingId = row._id + "_"+cellMap;
    }
    componentDidMount(){
        if(this.props.editingId === this.editingId){
            if(this.props.editingPackageId)
                $("#"+this.editingId+"_"+this.props.editingPackageId).focus();
            else $("#"+this.editingId).focus();
        }
    }
    handleChange = (row, cellMap) => e => {
        const {lPrice, pPrice} = row;
        const value = parseInt(e.target.value);
        if(cellMap === "sPrice"){

        }else if(cellMap === "lPrice"){
            if(!isNaN(value)){
                if(pPrice) row.cost = pPrice + value;
                else row.cost = value;
            }else if(pPrice) row.cost = pPrice;
            else row.cost = 0;
        }else{
            if(!isNaN(value)){
                if(lPrice) row.cost = lPrice + value;
                else row.cost = value;
            }else if(lPrice) row.cost = lPrice;
            else row.cost = 0;
        }
        if(this.props.setEditingId)
            this.props.setEditingId(this.editingId);
        
        row[cellMap] = value;
        this.props.updateData(row, cellMap);
    }
    handlePurchasePackageInput = (row, cellMap, packageId) => e => {
        let value = parseInt(e.target.value);
        if(cellMap === "sPrice"){
            if(row.sPrice)
                row.sPrice[packageId] = value ? value : 0;
            else row.sPrice = {[packageId] : value ? value : 0};
        }else{
            if(row.pPackages){
                row.pPackages[packageId] = value ? value : 0;
            }else row.pPackages = {[packageId] : value ? value : 0};
        }
        if(this.props.setEditingId)
            this.props.setEditingId(this.editingId, packageId);
        this.props.updateData(row, cellMap);
    }
    calculateTotalSellingUnits(row, cellMap){
        const {
            [stockStrings.itemPackaging] : itemPackaging,
        } = this.props;
        let totalDefaultPurchasePackageCount = 0;
        const {sellingPackageId, pPackages} = row;
        const {packagingId, counts} = row.packaging || {};
        if(packagingId){
            const {item : selectedItemPackaging} = itemPackaging.getFirstObjectByPropValue(
                "_id", packagingId
            ) || {};
            if(selectedItemPackaging && selectedItemPackaging.itemPackageIds){
                const {itemPackageIds} = selectedItemPackaging;
                let totalMinPackageCount = 1;
                let totalMinPurchaseCount = 0;
                for (let i = 0; i < counts.length; i++) {
                    const packageCount = counts[i] || 0;
                    totalMinPackageCount *= packageCount;
                    if(pPackages && pPackages[itemPackageIds[i]]){
                        const purchaseCount = pPackages[itemPackageIds[i]] || 0;
                        totalMinPurchaseCount += totalMinPackageCount * purchaseCount;
                    }else {

                    }
                }
                row.totalMinPackageCount = totalMinPackageCount;
                totalMinPackageCount = 1;
                if(totalMinPurchaseCount){
                    for (let i = 0; i < counts.length; i++) {
                        const packageCount = counts[i];
                        if(sellingPackageId === itemPackageIds[i])
                            break;
                        totalMinPackageCount *= packageCount;                        
                    }
                    totalDefaultPurchasePackageCount = totalMinPurchaseCount / totalMinPackageCount;
                }
            }
        }
        return totalDefaultPurchasePackageCount;
    }
    calculateExpectedIncome(row, cellMap){
        let income = 0;
        if(row.sPrice){
            for (const packageId in row.sPrice) {
                if (row.sPrice.hasOwnProperty(packageId)) {
                    const price = row.sPrice[packageId];
                    if(row.pPackages && row.pPackages[packageId]){
                        const purchasePackages = row.pPackages[packageId];
                        income += price * purchasePackages;
                    }
                }
            }
        }
        return income;
    }
    calculateExpectedProfit = (row, cellMap)=>{
        const expectedIncome = this.calculateExpectedIncome(row, cellMap);
        const totalCost = row.cost || 0;
        return expectedIncome - totalCost;
    }
    render() {
        const { classes, row, cellMap,
            [stockStrings.itemForms] : itemForms,
            [stockStrings.stockCategories] : stockCategories,
            [stockStrings.itemPackages] : itemPackages,
            [stockStrings.itemPackaging] : itemPackaging,
        } = this.props;
        switch(cellMap){
            case "exProfit" : 
                return <TableCell className={classes.cell}>
                    {Number(this.calculateExpectedProfit(row, cellMap)).toLocaleString()}
                </TableCell>
            case "exIncome" : 
                return <TableCell className={classes.cell}>
                    {Number(this.calculateExpectedIncome(row, cellMap)).toLocaleString()}
                </TableCell>
            case "tsUnits" : //console.log(row)                
                let sellingPackage;
                const {item : sellingPackageFilter} = itemPackages.getFirstObjectByPropValue("_id", row.sellingPackageId);

                if(sellingPackageFilter){
                    sellingPackage = sellingPackageFilter.name;
                }
                return <TableCell className={classes.cell}>
                    {sellingPackage +": "+ this.calculateTotalSellingUnits(row, cellMap)}
                </TableCell>
            case "sPrice" : 
            case "pPackages" : 
                let packaging = row.packaging;
                const {item : packagingItem} = itemPackaging.getFirstObjectByPropValue("_id", packaging.packagingId);
                return <TableCell className={classes.cell}>
                    {packagingItem && packagingItem.itemPackageIds &&
                    packagingItem.itemPackageIds.map((item, index)=>{
                        const {item : packageItem} = itemPackages.getFirstObjectByPropValue("_id", item) || {};
                        if(!packageItem) return;    
                        return <div key={index} style={{display : "flex", alignItems:"center"}}>
                            {packageItem.name}:<TextField 
                                value={row[cellMap] ? row[cellMap][item] : 0}
                                style={{minWidth : 50}}
                                inputProps={{
                                    id : this.editingId + "_"+item,
                                    style : {
                                        direction : "rtl"
                                    }
                                }}
                                onChange={this.handlePurchasePackageInput(row, cellMap, item)}
                                type="number"/>
                        </div>
                    })}
                </TableCell>;
            case "pPrice" :
            case "lPrice" :
                return <TableCell className={classes.cell}>
                    <TextField
                        style={{minWidth : 50}}
                        ref={e=>this.numberInput = e}
                        inputProps={{
                            id : this.editingId
                        }}
                        value={row[cellMap] ? row[cellMap] : 0} 
                        type="number" 
                        onChange={this.handleChange(row, cellMap)}/>
                </TableCell>
            case 'supplier' :
                return <TableCell className={classes.cell}>
                    {row[cellMap].name}
                </TableCell>
            default : return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
}


_NewStockCellMapFormat.propTypes = {
    classes : PropTypes.object.isRequired,
    setEditingId : PropTypes.func,
    editingId : PropTypes.string,
    updateData : PropTypes.func,
    editingPackageId : PropTypes.number,
};
const mapStateToProps = ({stockReducer}) => ({
    [stockStrings.itemForms] : stockReducer[stockStrings.itemForms],
    [stockStrings.stockCategories] : stockReducer[stockStrings.stockCategories],
    [stockStrings.itemPackages] : stockReducer[stockStrings.itemPackages],
    [stockStrings.itemPackaging] : stockReducer[stockStrings.itemPackaging],
})


export const NewStockCellMapFormat = connect(mapStateToProps)(withStyles(style)(_NewStockCellMapFormat));
export {NewStockCellMapFormat as default}