import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { routeNamesInventory } from '../../../routeNames';
import { ItemSelection, invProductActions } from '../../../INVProducts';
import { stockStrings } from '../../config';
import { TableCell, TextField, FormControlLabel, Switch, FormControl, Button } from '@material-ui/core';
import { stockActions } from '../../actions';
import NewStockCellMapFormat from './NewStockCellMapFormat';
import { inventoryUtil, headerActions, headerStrings, breadCrumbActions, mainStageHeaderAction, 
    mainStageHeaderStrings, MyDialog, MyTable, HighlightedInfo} from '../../../utils';


const style = theme => ({
    root: {
        marginTop : 30
    },
    addStockBtn : {
        backgroundColor : inventoryUtil.getTheme().secondary,
        color : inventoryUtil.getTheme().white
    },
    grow : {
        display : "flex", 
        flexGrow : 1,
    }
})
class _NewStock extends Component {
    constructor(props) {
        super(props);
        this.state = {
            itemDialogOpen : false,
            selectedItems : "",
            singleLP : false,
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "New Stock",
            [headerStrings.backButtonAction] : ()=>{}
        })(dispatch);
        breadCrumbActions.addToBreadCrumb([
            {name : "New Stock", path : routeNamesInventory.newStock}
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.buttons] : [
                {value: "Select Items", onClick : ()=>this.setState({itemDialogOpen : true})}
            ]
        })(dispatch);

    }
    componentDidMount(){
        
        //remove this later today
        invProductActions.getStockCategoryItems(1, (done, result)=>{
            console.log(result);
            if(done) this.setState({selectedItems: result})
        })(this.props.dispatch)

        const {
            dispatch, 
            [stockStrings.itemForms] : itemForms,
            [stockStrings.stockCategories] : stockCategories,
            [stockStrings.itemPackages] : itemPackages,
            [stockStrings.itemPackaging] : itemPackaging,
        } = this.props;
        if(!itemForms) stockActions.getItemFroms()(dispatch);
        if(!stockCategories) stockActions.getStockCategories()(dispatch);
        if(!itemPackages) stockActions.getItemPackages()(dispatch);
        if(!itemPackaging) stockActions.getItemPackaging()(dispatch);
    }
    
    getSelecteditems = (itemIndexes, selectedItems) => {
        this.setState({selectedItems})
    }
    setEditingId = (editingId, packageId)  => {
        this.editingInputId = editingId;
        this.editingPackageId = packageId;
    }
    cellMapFormat = superProps => props => <NewStockCellMapFormat {...props} {...superProps}/>
    updateData = (row, cellMap) => {
        let selectedItems = [...this.state.selectedItems];
        const {item : rowItem, index} = selectedItems.getFirstObjectByPropValue("_id", row._id) || {};
        if(rowItem){
            selectedItems[index] = {...row};
            this.setState({selectedItems});
        }
    }
    singleLPHandler = e => {
        this.setState({singleLP: e.target.checked});
    }
    render() {
        const {classes} = this.props;
        const { itemDialogOpen, selectedItems, singleLP } = this.state;
        let header = ["Item", "Brands", "Supplier", "Company", "Purchase Packages (counts)", "Total Selling Units", "Purchase Price"];
        if(!singleLP) header.push("Landing Price");
        header.push("Total Cost", "Selling Price", "Expected Income", "Expected Profit");
        let dataMap = ["name", "brand", "supplier", "company", "pPackages", "tsUnits", "pPrice"];
        if(!singleLP) dataMap.push("lPrice");
        dataMap.push("cost", "sPrice", "exIncome", "exProfit");
        return (
            <div className={classes.root}>
                {/* you can add or remove supplier column 
                ** use single landing price
                */}
                <HighlightedInfo type="primary" closable>
                    Use the general landing switch to put the landing (logistics) price 
                    for all the products at once.
                </HighlightedInfo>
                <HighlightedInfo closable>
                    Fill in the quantity of the product (in packages) but first,
                    then the cost/purchase price and the sales prices for each of the packages,
                    the system automatically calculate the expected income and profit
                </HighlightedInfo>
                <div style={{margin: 10, display : "flex", alignItems : "center"}}>
                    <FormControlLabel
                        label="Single landing Price"
                        control={<Switch
                            size="small"
                            onChange={this.singleLPHandler.bind(this)}
                            checked={singleLP}/>}/>
                    {singleLP && <TextField 
                        label="General landing price"
                        placeholder="landing price" 
                        type="number"/>}
                    <div className={classes.grow}/>
                    <FormControl>
                        <Button className={classes.addStockBtn}>Add Stock</Button>
                    </FormControl>
                </div>
                <MyTable
                    header={header}
                    dataMap={dataMap}
                    data={selectedItems || []}
                    CellMap={this.cellMapFormat({
                        updateData : this.updateData.bind(this),
                        setEditingId : this.setEditingId.bind(this),
                        editingId : this.editingInputId,
                        editingPackageId : this.editingPackageId,
                    })}
                    />
                <MyDialog open={itemDialogOpen}>
                    <ItemSelection
                        closeDialog={()=>this.setState({itemDialogOpen : false})}
                        continueAction={this.getSelecteditems.bind(this)}/>
                </MyDialog>
            </div>
        );
    }
}


_NewStock.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({stockReducer}) => ({
    [stockStrings.itemForms] : stockReducer[stockStrings.itemForms],
    [stockStrings.stockCategories] : stockReducer[stockStrings.stockCategories],
    [stockStrings.itemPackages] : stockReducer[stockStrings.itemPackages],
    [stockStrings.itemPackaging] : stockReducer[stockStrings.itemPackaging],
})


export const NewStock = connect(mapStateToProps)(withStyles(style)(_NewStock));
export {NewStock as default}